(12009, 'ptBR', 'Derrotar L\'ura na Sede do Triunvirato com todos os integrantes do grupo afetados por Escuridão Acachapante no modo Mítico.', 'Lado Sombrio', '', 67186),
(12005, 'ptBR', 'Fazer com que Presanegra destrua 4 Baús do Caos Selados usando Salto das Sombras, depois derrotar Saprish na Sede do Triunvirato, no modo Mítico.', 'Soltou os caoschorros', '', 67186),
(12004, 'ptBR', 'Usar Rasgo do Caos para tirar Urjad do reino do Caos e, em seguida, derrotar Urjad e Zuraal, o Elevado, na Sede do Triunvirato no modo Mítico.', 'Boas-vindas ao Caos', '', 67186),
(9036, 'ptBR', 'Derrotar a Alta Sábia Viryx sem matar nenhum dos Constructos de Escudo, em Beira-céu, na dificuldade Heroica.', 'Monomania', '', 67186),
(9035, 'ptBR', 'Fazer com que os três Pilares de Cinza formem Clarões Solares ao mesmo tempo durante a luta contra Rukhran em Beira-céu na dificuldade Heroica.', 'Lá vem o Solis', '', 67186),
(9034, 'ptBR', 'Derrotar o Constructo Energizado em Beira-céu na dificuldade Heroica.', 'Ampliar... Aprimorar', '', 67186),
(9033, 'ptBR', 'Derrotar Ranjit em Beira-céu sem receber dano de nenhuma das habilidades abaixo, na dificuldade Heroica: Lâmina Giratória, Barreira de Vento, Quatro Ventos, Clarão da Lente.', 'Pronto pro raide IV', '', 67186),
(4525, 'ptBR', 'Limpar o corredor que precede o Senhor do Flagelo Tyrannus no Fosso de Saron, no modo Heroico, sem que ninguém recebe dano dos sincelos na primeira tentativa.', 'Não Olhe para Cima', '', 67186),
(4524, 'ptBR', 'No modo Heroico, derrotar o Mestre Forjador Criomal no Fosso de Saron antes que um jogador acumule Permafrio 11 vezes.', 'Masmorra abaixo de onze', '', 67186),
