INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'ptBR', 'Núcleo Caótico Nebuloso', 'Pode ser transmutado em um equipamento poderoso ao derrotar inimigos fortes em raides de Midnight Série 1 ou concluir masmorras Míticas+, Imersões Abundantes e Caças à Presa no modo Pesadelo.', 67186),
(3347, 'ptBR', 'Brasão Auroral Mítico', 'Usado para aprimorar equipamentos Míticos na Série 1 de Midnight até os níveis de item 276–289.  \n\nQuando usado para a criação, define o nível criado para 272–285 de acordo com a Qualidade.\n\nObtido nas seguintes atividades:\n\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no modo Mítico\n- Masmorras de Pedra-chave Mítica (+9 e acima)', 67186),
(3346, 'ptBR', 'Brasão Auroral do Herói', 'Usado para aprimorar equipamentos de Herói na Série 1 de Midnight até os níveis de item 263–276. Obtido nas seguintes atividades:\n\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no modo Heroico\n- Masmorras de Pedra-chave Mítica (+4 a +8)\n- Imersões (Grau 11)\n- Recompensa do Caça-tesouros (Grau 8+)\n- Caças às Presas (Pesadelo)', 67186),
(3345, 'ptBR', 'Brasão Auroral do Herói', 'Usado para aprimorar equipamentos de Herói na Série 1 de Midnight até os níveis de item 263–276. \n\nQuando usado para a criação, define o nível criado para 259–272 de acordo com a Qualidade.\n\nObtido nas seguintes atividades:\n\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no modo Heroico\n- Masmorras de Pedra-chave Mítica (+4 a +8)\n- Imersões (Grau 11)\n- Recompensa do Caça-tesouros (Grau +8)\n- Caças às Presas (Pesadelo)', 67186),
(3344, 'ptBR', 'Brasão Auroral do Campeão', 'Usado para aprimorar equipamentos de Campeão na Série 1 de Midnight até os níveis de item 250–263. Obtido nas seguintes atividades:\n\n- Eventos externos semanais\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no modo Normal\n- Masmorras Míticas da Série\n- Masmorras de Pedra-chave Mítica (+2 a +3)\n- Imersões (Graus 7 a 10)\n- Recompensa do Caça-tesouros (Graus 6 a 7)\n- Caças às Presas (Pesadelo)', 67186),
(3343, 'ptBR', 'Brasão Auroral do Campeão', 'Usado para aprimorar equipamentos de Campeão na Série 1 de Midnight até os níveis de item 250–263. Obtido nas seguintes atividades:\n\n- Eventos externos semanais\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no modo Normal\n- Masmorras Míticas da Série\n- Masmorras de Pedra-chave Mítica (+2 a +3)\n- Imersões (Graus 7 a 10)\n- Recompensa do Caça-tesouros (Graus 6 a 7)\n- Caças às Presas (Pesadelo)', 67186),
(3342, 'ptBR', 'Brasão Auroral do Veterano', 'Usado para aprimorar equipamentos de Veterano na Série 1 de Midnight até os níveis de item 237–250. Obtido nas seguintes atividades:\n\n- Eventos externos repetíveis\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no Localizador de Raides\n- Masmorras Heroicas da Série\n- Imersões (Graus 5 a 6)\n- Recompensa do Caça-tesouros (Graus 4 a 5)\n- Caças às Presas (Difícil)', 67186),
(3341, 'ptBR', 'Brasão Auroral do Veterano', 'Usado para aprimorar equipamentos de Veterano na Série 1 de Midnight até os níveis de item 237–250. \n\nQuando usado para a criação, define o nível criado para 233–246 de acordo com a Qualidade.\n\nObtido nas seguintes atividades:\n\n- Eventos externos repetíveis\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no Localizador de Raides\n- Masmorras Heroicas da Série\n- Imersões (Graus 5 a 6)\n- Recompensa do Caça-tesouros (Graus 4 a 5)\n- Caças às Presas (Difícil)', 67186),
(3418, 'ptBR', 'Núcleo Caótico Nebuloso', 'Pode ser transmutado em um equipamento poderoso ao derrotar inimigos fortes em raides de Midnight Série 1 ou concluir masmorras Míticas+, Imersões Abundantes e Caças à Presa no modo Pesadelo.', 67186),
(3391, 'ptBR', 'Brasão Auroral do Aventureiro', 'Usado para aprimorar equipamentos de Aventureiro na Série 1 de Midnight até os níveis de item 224–237. Obtido nas seguintes atividades:\n\n- Eventos externos repetíveis\n- Imersões de Grau 4\n- Caças às Presas (Normal)', 67186),
(3383, 'ptBR', 'Brasão Auroral do Aventureiro', 'Usado para aprimorar equipamentos de Aventureiro na Série 1 de Midnight até os níveis de item 224–237. \n\nQuando usado para a criação, define o nível criado para 220–233 de acordo com a Qualidade.\n\nObtido nas seguintes atividades:\n\n- Eventos externos repetíveis\n- Imersões de Grau 4\n- Caças às Presas (Normal)', 67186),
(3348, 'ptBR', 'Brasão Auroral Mítico', 'Usado para aprimorar equipamentos Míticos na Série 1 de Midnight até os níveis de item 276–289. Obtido nas seguintes atividades:\n\n- Torre do Caos, Fenda Onírica e Marcha em Quel\'Danas no modo Heroico\n- Masmorras de Pedra-chave Mítica (+9 e acima)', 67186);
