INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'ptBR', 'Tanques', '$bullet; O Acumulista junta recursos da pilha mais próxima durante |cFF2959D3|Hspell:1235072|h[Medidas Providenciais]|h|r.\n$bullet; Cogumelos Podres aplicam |cFF2959D3|Hspell:1234846|h[Esporos Tóxicos]|h|r com o contato, impedindo que explodam num |cFF2959D3|Hspell:1245593|h[Estouro Pútrido]|h|r.\n$bullet; |cFF2959D3|Hspell:1234681|h[Urro Voraz]|h|r e |cFF2959D3|Hspell:1235125|h[Urro Substancial]|h|r causam dano elevado a todos os jogadores.', 67186),
(32669, 'ptBR', 'Visão Geral', 'O Acumulista impede que as reservas dele sejam furtadas a qualquer custo, lançando |cFF2959D3|Hspell:1235072|h[Medidas Providenciais]|h|r ao atingir 90%, 60% e 30% dos pontos de vida, fortalecendo uma das habilidades dele.\n\nAo atingir 100 de energia, ele lança |cFF2959D3|Hspell:1234233|h[Suprimentos Estragados]|h|r pela arena, criando Cogumelos Podres por 12 s. Com o contato, os cogumelos aplicam |cFF2959D3|Hspell:1234846|h[Esporos Tóxicos]|h|r e são destruídos, evitando o |cFF2959D3|Hspell:1245593|h[Estouro Pútrido]|h|r.', 67186),
(31527, 'ptBR', 'Carga Proibida', 'Um carregamento que deve ficar longe de olhares curiosos. Funciona como uma excelente cobertura.', 67186),
(31282, 'ptBR', 'Tanque', '$bullet; Kystia usa a |cFF2959D3|Hspell:1230289|h[Infusão Ilícita]|h|r para tornar Mordisco agressivo contra os jogadores.\n$bullet;Esquive-se do |cFF2959D3|Hspell:1253811|h[Spray Vil]|h|r de Mordisco.\n$bullet; Interrompa as |cFF2959D3|Hspell:1264095|h[Imagens Espelhadas]|h|r de Kystia.', 67186),
(31281, 'ptBR', 'Curadores', '$bullet; Kystia usa a |cFF2959D3|Hspell:1230289|h[Infusão Ilícita]|h|r para tornar Mordisco agressivo contra os jogadores.\n$bullet;Esquive-se do |cFF2959D3|Hspell:1253811|h[Spray Vil]|h|r de Mordisco.\n$bullet; Kystia causa muito dano a todos os jogadores enquanto está |cFF2959D3|Hspell:1265412|h[Desestabilizada]|h|r.', 67186),
(31280, 'ptBR', 'Causadores de Dano', '$bullet; Kystia usa a |cFF2959D3|Hspell:1230289|h[Infusão Ilícita]|h|r para tornar Mordisco agressivo contra os jogadores.\n$bullet;Esquive-se do |cFF2959D3|Hspell:1253811|h[Spray Vil]|h|r de Mordisco.\n$bullet; Interrompa as |cFF2959D3|Hspell:1264095|h[Imagens Espelhadas]|h|r de Kystia.', 67186),
(35862, 'ptBR', 'Section 18', '', 67186),
(35353, 'ptBR', 'Seção 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'ptBR', 'Seção 17', '', 67186),
(34733, 'ptBR', 'Astúcia de Xal\'atath', 'Xal\'atath trai os jogadores, revogando as barganhas dela e fazendo com que mortes subtraiam 15 segundos do tempo restante.', 67186),
(34732, 'ptBR', 'Fortificação', 'Inimigos normais têm 20% mais pontos de vida e causam até 20% a mais de dano.', 67186),
(34731, 'ptBR', 'Tirania', 'Chefes têm 25% a mais de pontos de vida. Chefes e seus lacaios causam até 15% a mais de dano.', 67186),
(34730, 'ptBR', 'Tirânica e Fortificada', 'Esses afixos fortalecem ainda mais os inimigos nas Masmorras de Pedra-chave Mítica. Um se ativa no Nível Mítico 7 e o outro no 10, mudando toda semana.', 67186),
(34727, 'ptBR', 'Barganha de Xal\'atath: Devorar', '', 67186),
(34725, 'ptBR', 'Barganha de Xal\'atath: Distorcido pelo Caos', '', 67186),
(34722, 'ptBR', 'Barganha de Xal\'atath: Pulsar', '', 67186),
(34720, 'ptBR', 'Nível Mítico 6', '$bullet;|cFF2959D3|Hspell:1284818|h[Orientação de Lindormi]|h|r foi removida.\n\nPersonagens com uma especialização de tanque podem falar com Lindormi perto do portal dos Percursos Temporais ou ao final de uma Masmorra de Pedra-chave para obter |cFF2959D3|Hspell:1295986|h[Brilho de Lindormi]|h|r, que continuará a destacar as forças inimigas.', 67186),
(35809, 'ptBR', 'Section 158', '', 67186),
(35491, 'ptBR', 'Seção 69', '', 67186),
(35490, 'ptBR', 'Seção 70', '', 67186),
(35489, 'ptBR', 'Seção 76', '', 67186),
