INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'ptBR', 'Saudações, $Gacólito:acólita;!\n\nContemple a maravilha deste domínio, que transborda de ABUNDÂNCIA GLORIOSA! Ela fervilha, se assoma e não se deixa conter!\n\nSua devoção ao meu ser divino merece uma pequena benevolência. Desta vez, na forma de Abundância Impoluta!\n\nE saiba de uma coisa, $Ggentil acólito:gentil acólita;: certas oferendas, como a Vitalidade Fundida, aparecem com outros fornecedores. Talvez você os encontre caso decida se aventurar nas Profundezas de Zul\'Aman.\n\nDesejo a você as melhores colheitas!\n\nDundun, Loa da Abundância', 67186);
